let line = String(msg.payload).trim();
if (!line) return null;

let parts = line.split(",");

if (parts.length < 2) return null;

msg.raw = line;
msg.time = parts[0];      // keep as text
msg.type = parts[1];

if (msg.type === "TLM" && parts.length >= 5) {
    msg.target = parts[2];
    msg.parameter = parts[3];
    msg.value = parts[4];
}
else if (msg.type === "ACK" && parts.length >= 4) {
    msg.target = parts[2];
    msg.value = parts[3];
}
else if (msg.type === "ERR" && parts.length >= 3) {
    msg.error = parts[2];

    if (parts.length >= 4) {
        msg.errorContext = parts[3];
        try {
            msg.errorContextDecoded = decodeURIComponent(parts[3]);
        } catch (err) {
            msg.errorContextDecoded = parts[3];
        }
    }
}

return msg;

let state = flow.get("satState") || {};

if (!state.tlm) {
    state.tlm = {};
}
if (!state.lastAck) {
    state.lastAck = null;
}
if (!state.lastErr) {
    state.lastErr = null;
}
if (!state.time) {
    state.time = null;
}

if (msg.time) {
    state.time = msg.time;
}

if (msg.type === "TLM") {
    if (!msg.target || !msg.parameter) {
        return null;
    }

    if (!state.tlm[msg.target]) {
        state.tlm[msg.target] = {};
    }

    state.tlm[msg.target][msg.parameter] = {
        value: msg.value,
        time: msg.time
    };
}
else if (msg.type === "ACK") {
    state.lastAck = {
        target: msg.target || null,
        value: msg.value || null,
        time: msg.time || null
    };
}
else if (msg.type === "ERR") {
    state.lastErr = {
        error: msg.error || null,
        context: msg.errorContext || null,
        contextDecoded: msg.errorContextDecoded || null,
        time: msg.time || null
    };
}

flow.set("satState", state);

msg.state = state;
return msg;

let s = msg.state || {};
let tlm = s.tlm || {};
const freshnessThresholdMs = 10000;

function getValue(target, parameter, fallback = "") {
    if (tlm[target] && tlm[target][parameter]) {
        return tlm[target][parameter].value;
    }
    return fallback;
}

function getTime(target, parameter, fallback = "") {
    if (tlm[target] && tlm[target][parameter]) {
        return tlm[target][parameter].time;
    }
    return fallback;
}

let payload = {
    time: s.time || "",
    freshnessThresholdMs,
    lastAck: s.lastAck,
    lastErr: s.lastErr
};

function addField(key, label, target, parameter) {
    payload[key] = getValue(target, parameter);
    payload[key + "Label"] = label;
    payload[key + "Time"] = getTime(target, parameter);
}

