    ],
    metricRows: []
};
return msg;

if (!msg.payload.lastAck) {
    msg.payload = "";
    return msg;
}
msg.payload = [msg.payload.lastAck.time, msg.payload.lastAck.target, msg.payload.lastAck.value]
    .filter(v => v !== null && v !== undefined && v !== "")
    .join(" | ");
return msg;

if (!msg.payload.lastErr) {
    msg.payload = "";
    return msg;
}
msg.payload = [
    msg.payload.lastErr.time,
    msg.payload.lastErr.error,
    msg.payload.lastErr.contextDecoded
]
    .filter(v => v !== null && v !== undefined && v !== "")
    .join(" | ");
return msg;

let color = String(msg.payload || "").toUpperCase();
if (!["RED", "GREEN", "BLUE"].includes(color)) {
    return null;
