let packetLog = flow.get("packetLog") || [];

packetLog.unshift({
    time: msg.time || "",
    packetType: msg.type || "",
    target: msg.target || "",
    parameter: msg.parameter || "",
    value: msg.value || msg.error || "",
    raw: msg.raw || ""
});

packetLog = packetLog.slice(0, 13);
flow.set("packetLog", packetLog);

return {
    payload: {
        rows: packetLog
    }
};

if (msg.type !== "ERR") {
