format:
.freshness-widget {
    height: 100%;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    text-align: center;
    overflow: hidden;
    padding: 0.1rem 0;
    box-sizing: border-box;
}

.freshness-label {
    font-size: 0.85rem;
    color: #FFFFFF;
    line-height: 1.1;
    margin: 0;
}

.freshness-value {
    margin-top: 0.1rem;
    font-size: 0.95rem;
    font-weight: 600;
    line-height: 1.05;
    transition: color 0.2s ease;
}

.freshness-fresh {
    color: #2e7d32;
}

.freshness-stale {
    color: #d32f2f;
}

.freshness-empty {
    color: #717171;
}

.summary-card {
    display: flex;
    flex-direction: column;
    gap: 0.45rem;
    height: 100%;
    padding: 0.2rem 0;
    box-sizing: border-box;
}

.summary-grid {
    display: grid;
    gap: 0.35rem 0.6rem;
    align-items: stretch;
}

.summary-grid-status {
    grid-template-columns: repeat(4, minmax(0, 1fr));
}

.summary-grid-status-3 {
    grid-template-columns: repeat(3, minmax(0, 1fr));
}

.summary-grid-metrics {
    grid-template-columns: repeat(2, minmax(0, 1fr));
}

.summary-item {
    min-height: 0;
}

